"use client";

import { useState } from "react";
import KakaoMap from "@/components/KakaoMap"; // 경로 확인 필요
import "./pharmacy.css";

// 카카오맵 Place 데이터 타입 정의 (필요한 필드만)
interface Place {
  id: string;
  place_name: string;
  address_name: string;
  phone: string;
  place_url: string;
  x: string; // 경도 (longitude)
  y: string; // 위도 (latitude)
  distance?: string; // 내 위치 기준 거리 (미터)
}

export default function PharmacyPage() {
  const [pharmacies, setPharmacies] = useState<Place[]>([]);
  const [isLoading, setIsLoading] = useState(true);

  // KakaoMap 컴포넌트에서 데이터가 로드되면 실행되는 콜백
  const handlePharmaciesLoaded = (data: any[]) => {
    setPharmacies(data);
    setIsLoading(false);
  };

  return (
    <div className="pharmacy-container">
      {/* 헤더 영역 */}
      <div className="pharmacy-header">
        <h1 className="pharmacy-title">약국 찾기 🏥</h1>
        <p className="pharmacy-desc">
          지도를 움직여 <strong>[현 위치에서 재검색]</strong> 버튼을 눌러보세요.
        </p>
      </div>

      {/* 지도 영역 (KakaoMap 컴포넌트 사용) */}
      <div className="map-section">
        <KakaoMap onPharmaciesLoaded={handlePharmaciesLoaded} />
      </div>

      {/* 결과 리스트 영역 */}
      <div className="pharmacy-list-section">
        <div className="list-header">
          <h3>
            검색 결과 <span className="count">{pharmacies.length}</span>건
          </h3>
        </div>

        {isLoading ? (
          <div className="loading-msg">약국 정보를 불러오는 중...</div>
        ) : pharmacies.length > 0 ? (
          <div className="pharmacy-grid">
            {pharmacies.map((place) => (
              <div key={place.id} className="pharmacy-card">
                <div className="card-body">
                  <h4 className="place-name">
                    <a href={place.place_url} target="_blank" rel="noopener noreferrer">
                      {place.place_name}
                    </a>
                  </h4>
                  <p className="place-addr">{place.address_name}</p>
                  <p className="place-phone">{place.phone || "전화번호 없음"}</p>
                </div>
                <div className="card-footer">
                  <a
                    href={`https://map.kakao.com/link/to/${place.place_name},${place.y},${place.x}`}
                    target="_blank"
                    rel="noopener noreferrer"
                    className="btn-path"
                  >
                    길찾기 ↗
                  </a>
                </div>
              </div>
            ))}
          </div>
        ) : (
          <div className="empty-msg">
            <p>
              이 근처에는 약국이 없습니다. 😭<br />
              지도를 다른 지역으로 이동해보세요!
            </p>
          </div>
        )}
      </div>
    </div>
  );
}